import React, { useState } from 'react';
import { BrainCircuit, X } from 'lucide-react';
import { useProject } from '../context/ProjectContext';
import { Button, Card } from './ui';
import { ToastMessage } from '../types';

export const AuthModal = ({ isOpen, onClose, setToast }: { isOpen: boolean, onClose: () => void, setToast: (toast: ToastMessage) => void }) => {
    const { login, signup } = useProject();
    const [isLoginView, setIsLoginView] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [error, setError] = useState('');

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        let success = false;
        if (isLoginView) {
            success = await login(email, password);
            if (!success) setError('Invalid email or password.');
        } else {
            success = await signup(name, email, password);
            if (!success) setError('A user with this email already exists.');
        }

        if (success) {
            setToast({ message: isLoginView ? 'Logged in successfully!' : 'Account created!', type: 'success' });
            onClose();
        }
    };

    return (
        <div className="fixed inset-0 bg-gray-900 bg-opacity-75 flex justify-center z-[100] overflow-y-auto p-4 sm:p-10" onClick={onClose}>
            <Card className="w-full max-w-md my-auto transform transition-all relative" onClick={e => e.stopPropagation()} noPadding>
                <button 
                    onClick={onClose} 
                    className="absolute top-2 right-2 p-1 rounded-full text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 z-10"
                    aria-label="Close"
                >
                    <X className="w-6 h-6" />
                </button>
                <div className="flex">
                    <button onClick={() => setIsLoginView(true)} className={`flex-1 p-4 text-center font-semibold transition-colors ${isLoginView ? 'bg-white dark:bg-charcoal-800' : 'bg-gray-100 dark:bg-charcoal-900 hover:bg-gray-200 dark:hover:bg-charcoal-700'}`}>Login</button>
                    <button onClick={() => setIsLoginView(false)} className={`flex-1 p-4 text-center font-semibold transition-colors ${!isLoginView ? 'bg-white dark:bg-charcoal-800' : 'bg-gray-100 dark:bg-charcoal-900 hover:bg-gray-200 dark:hover:bg-charcoal-700'}`}>Sign Up</button>
                </div>
                <div className="p-6">
                    <div className="text-center mb-4">
                      <BrainCircuit className="w-10 h-10 text-brand-primary mx-auto" />
                      <h2 className="text-2xl font-bold mt-2">VibraEngineer</h2>
                    </div>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {!isLoginView && (
                            <div>
                                <label className="block text-sm font-medium">Name</label>
                                <input type="text" value={name} onChange={e => setName(e.target.value)} required className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-brand-primary focus:border-brand-primary sm:text-sm dark:bg-charcoal-700 dark:border-gray-600 dark:text-white" />
                            </div>
                        )}
                        <div>
                            <label className="block text-sm font-medium">Email</label>
                            <input type="email" value={email} onChange={e => setEmail(e.target.value)} required className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-brand-primary focus:border-brand-primary sm:text-sm dark:bg-charcoal-700 dark:border-gray-600 dark:text-white" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium">Password</label>
                            <input type="password" value={password} onChange={e => setPassword(e.target.value)} required className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-brand-primary focus:border-brand-primary sm:text-sm dark:bg-charcoal-700 dark:border-gray-600 dark:text-white" />
                        </div>
                        {error && <p className="text-sm text-red-500 font-medium">{error}</p>}
                        <Button type="submit" className="w-full mt-2">{isLoginView ? 'Login' : 'Create Account'}</Button>
                    </form>
                </div>
            </Card>
        </div>
    );
};

import React, { useState } from 'react';
import { X, Save, Download, Upload, User, BrainCircuit, LoaderCircle } from 'lucide-react';
import { useProject } from '../context/ProjectContext';
import { Button, Card } from './ui';
import { ToastMessage } from '../types';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    setToast: (toast: ToastMessage | null) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, setToast }) => {
    const { currentUser, updateUserProfile, project, updateProject } = useProject();
    const [name, setName] = useState(currentUser?.name || '');
    const [email, setEmail] = useState(currentUser?.email || '');
    const [occupation, setOccupation] = useState(currentUser?.occupation || '');
    const [aiModel, setAiModel] = useState(project?.aiModel || 'gemini-3-flash-preview');
    const [isSaving, setIsSaving] = useState(false);

    if (!isOpen) return null;

    const handleSave = () => {
        setIsSaving(true);
        updateUserProfile({ name, email, occupation });
        if (project) {
            updateProject({ ...project, aiModel });
        }
        setToast({ message: 'Settings updated successfully.', type: 'success' });
        setTimeout(() => {
            setIsSaving(false);
            onClose();
        }, 500);
    };

    const handleFullBackup = () => {
        const fullState = {
            currentUser,
            projects: JSON.parse(localStorage.getItem(`projects_${currentUser?.id}`) || '[]'),
            settings: { theme: localStorage.getItem('theme'), aiModel }
        };
        const blob = new Blob([JSON.stringify(fullState, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `vibra_engineer_backup_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        setToast({ message: 'Full system backup downloaded.', type: 'success' });
    };

    const handleFullRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const state = JSON.parse(event.target?.result as string);
                if (state.currentUser && state.projects) {
                    localStorage.setItem('vibe_currentUser', JSON.stringify(state.currentUser));
                    localStorage.setItem(`projects_${state.currentUser.id}`, JSON.stringify(state.projects));
                    setToast({ message: 'Full system restored. Please reload the page.', type: 'success' });
                    setTimeout(() => window.location.reload(), 1500);
                } else {
                    throw new Error('Invalid backup file structure.');
                }
            } catch (err) {
                setToast({ message: 'Failed to restore backup. Invalid format.', type: 'error' });
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="fixed inset-0 bg-gray-900 bg-opacity-75 flex items-center justify-center z-[200] p-4" onClick={onClose}>
            <Card className="w-full max-w-lg" onClick={e => e.stopPropagation()} noPadding>
                <div className="flex items-center justify-between p-4 border-b dark:border-charcoal-700">
                    <h2 className="text-xl font-bold">App Settings</h2>
                    <button onClick={onClose} className="p-1 rounded-full text-gray-500 hover:bg-gray-100 dark:hover:bg-charcoal-700">
                        <X className="w-6 h-6" />
                    </button>
                </div>
                <div className="p-6 space-y-6">
                    {/* Profile Section */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-500 uppercase flex items-center gap-2">
                            <User className="w-4 h-4" /> User Profile
                        </h3>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-medium mb-1">Name</label>
