                                <option value="gemini-3-flash-preview">Gemini 3 Flash (Fast)</option>
                                <option value="gemini-3-pro-preview">Gemini 3 Pro (Complex Reasoning)</option>
                                <option value="gemini-2.5-flash-lite-latest">Gemini 2.5 Flash Lite</option>
                            </select>
                        </div>
                    </div>

                    {/* Backup & Restore */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-500 uppercase">System Maintenance</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <Button variant="outline" size="sm" onClick={handleFullBackup} className="w-full">
                                <Download className="w-4 h-4 mr-2" /> Backup
                            </Button>
                            <label className="w-full">
                                <input type="file" onChange={handleFullRestore} className="hidden" accept=".json" />
                                <div className="flex items-center justify-center w-full px-3 py-2 text-sm border-2 border-dashed rounded-lg cursor-pointer hover:bg-gray-100 dark:hover:bg-charcoal-800/50 dark:border-charcoal-700 border-gray-300 dark:border-gray-600">
                                    <Upload className="w-4 h-4 mr-2" /> Restore
                                </div>
                            </label>
                        </div>
                    </div>

                    <div className="flex justify-end pt-4 border-t dark:border-charcoal-700">
                        <Button onClick={handleSave} disabled={isSaving}>
                            {isSaving ? <LoaderCircle className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
                            Save Settings
                        </Button>
                    </div>
                </div>
            </Card>
        </div>
    );
};

// Helper function to convert ArrayBuffer to hex string
function bufferToHex(buffer: ArrayBuffer): string {
  return [...new Uint8Array(buffer)]
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
}

// Helper function to convert hex string to ArrayBuffer
function hexToBuffer(hex: string): ArrayBuffer {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
  }
  return bytes.buffer;
}

/**
 * Hashes a password with a random salt using SHA-256.
 * @param password The plaintext password to hash.
 * @returns A promise that resolves to a string containing the salt and hash, separated by a dot.
 */
export async function hashPassword(password: string): Promise<string> {
  // Fallback for non-secure contexts where crypto.subtle might be missing
  if (!window.crypto || !window.crypto.subtle) {
      console.warn("Secure context required for Web Crypto API. Using simple mock hash for insecure dev environment.");
      return `mock_salt.${btoa(password)}`;
  }

  const salt = window.crypto.getRandomValues(new Uint8Array(16));
  const encoder = new TextEncoder();
  const data = encoder.encode(password);

  // Combine salt and password for hashing
  const saltedData = new Uint8Array(salt.length + data.length);
  saltedData.set(salt);
  saltedData.set(data, salt.length);

  const hashBuffer = await window.crypto.subtle.digest('SHA-256', saltedData);

  const saltHex = bufferToHex(salt);
  const hashHex = bufferToHex(hashBuffer);

  return `${saltHex}.${hashHex}`;
}

/**
 * Verifies a plaintext password against a stored hash (salt included).
 * @param password The plaintext password to verify.
 * @param storedHash The stored string containing the salt and hash.
 * @returns A promise that resolves to true if the password is correct, false otherwise.
 */
export async function verifyPassword(password: string, storedHash: string): Promise<boolean> {
  try {
    const [saltHex, originalHashHex] = storedHash.split('.');

    // Handle mock hash from insecure context fallback
    if (saltHex === 'mock_salt') {
        return originalHashHex === btoa(password);
    }

    if (!saltHex || !originalHashHex) {
      return false; // Invalid hash format
    }

    if (!window.crypto || !window.crypto.subtle) {
         console.warn("Secure context required for Web Crypto API. Cannot verify real hash in insecure environment.");
         return false;
    }

    const salt = hexToBuffer(saltHex);
    const encoder = new TextEncoder();
    const data = encoder.encode(password);

    // Combine salt and password for hashing
    const saltedData = new Uint8Array(salt.byteLength + data.length);
    saltedData.set(new Uint8Array(salt));
    saltedData.set(data, salt.byteLength);

    const hashBuffer = await window.crypto.subtle.digest('SHA-256', saltedData);
    const hashHex = bufferToHex(hashBuffer);

    return hashHex === originalHashHex;
  } catch (error) {
    console.error("Error during password verification:", error);
    return false;
  }
}

export function generateUUID(): string {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
}

import { Project, User } from '../types';

const DB_NAME = 'VibeDB';
const DB_VERSION = 1;
const STORES = {
  USERS: 'users',
  PROJECTS: 'projects'
};

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORES.USERS)) {
        const userStore = db.createObjectStore(STORES.USERS, { keyPath: 'id' });
        userStore.createIndex('email', 'email', { unique: true });
      }
      if (!db.objectStoreNames.contains(STORES.PROJECTS)) {
        const projectStore = db.createObjectStore(STORES.PROJECTS, { keyPath: 'id' });
        projectStore.createIndex('userId', 'userId', { unique: false });
      }
    };
  });
};

export const dbService = {
  async getAllUsers(): Promise<User[]> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.USERS, 'readonly');
      const store = transaction.objectStore(STORES.USERS);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  },

  async getUser(email: string): Promise<User | undefined> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.USERS, 'readonly');
      const store = transaction.objectStore(STORES.USERS);
      const index = store.index('email');
      const request = index.get(email);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  },

  async getUserById(id: string): Promise<User | undefined> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.USERS, 'readonly');
      const store = transaction.objectStore(STORES.USERS);
      const request = store.get(id);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  },

  async saveUser(user: User): Promise<void> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.USERS, 'readwrite');
      const store = transaction.objectStore(STORES.USERS);
      const request = store.put(user);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  async getProjects(userId: string): Promise<Project[]> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.PROJECTS, 'readonly');
      const store = transaction.objectStore(STORES.PROJECTS);
      const index = store.index('userId');
      const request = index.getAll(userId);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  },

  async saveProject(project: Project): Promise<void> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.PROJECTS, 'readwrite');
      const store = transaction.objectStore(STORES.PROJECTS);
      const request = store.put(project);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  async deleteProject(id: string): Promise<void> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORES.PROJECTS, 'readwrite');
      const store = transaction.objectStore(STORES.PROJECTS);
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
};

import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { Project, User, Phase, Comment, Task } from '../types';
import { hashPassword, verifyPassword, generateUUID } from '../utils/crypto';
import { dbService } from '../services/db';

interface ProjectContextType {
    project: Project | null;
    setProject: React.Dispatch<React.SetStateAction<Project | null>>;
    projects: Project[];
    currentUser: User | null;
    setCurrentUser: React.Dispatch<React.SetStateAction<User | null>>;
    theme: string;
    setTheme: (theme: string) => void;

    // Auth & Project list management
    login: (email: string, pass: string) => Promise<boolean>;
    signup: (name: string, email: string, pass: string) => Promise<boolean>;
    logout: () => void;
    updateUserProfile: (updates: Partial<User>) => void;

    // Project lifecycle management
    updateProject: (updatedProject: Project) => void;
    addProject: (newProject: Project) => void;
    deleteProject: (projectId: string) => void;
    updateProjectDetails: (projectId: string, updates: { requirements: string, constraints: string }) => void;
    updatePhase: (projectId: string, phaseId: string, updates: Partial<Phase>) => void;
    addComment: (projectId: string, phaseId: string, text: string) => void;
    addTask: (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => void;
    updateTask: (projectId: string, updatedTask: Task) => void;
    isLoading: boolean;
}

const ProjectContext = createContext<ProjectContextType | undefined>(undefined);

interface ProjectProviderProps {
    children?: ReactNode;
}

export const ProjectProvider = ({ children }: ProjectProviderProps) => {
    const [project, setProject] = useState<Project | null>(null);
    const [projects, setProjects] = useState<Project[]>([]);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [theme, setThemeState] = useState(() => {
        if (typeof window === 'undefined') return 'dark';
        return localStorage.getItem('theme') || 'dark';
    });

    const setTheme = (newTheme: string) => {
        if (newTheme === 'dark') {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
        localStorage.setItem('theme', newTheme);
        setThemeState(newTheme);
    };

    useEffect(() => {
        setTheme(theme);
    }, []);

    // Load current user and projects from DB on initial load
    useEffect(() => {
        const initData = async () => {
            try {
                // Check for persisted session ID
                const savedUserId = localStorage.getItem('vibe_currentUserId');
                if (savedUserId) {
                    const user = await dbService.getUserById(savedUserId);
                    if (user) {
                        setCurrentUser(user);

                        // Load projects for this user
                        const userProjects = await dbService.getProjects(user.id);
                        setProjects(userProjects);

                        // Load active project ID
                        const activeProjectId = localStorage.getItem(`activeProject_${user.id}`);
                        if (activeProjectId) {
                            const activeProject = userProjects.find((p: Project) => p.id === activeProjectId);
                            if (activeProject) setProject(activeProject);
                        }
                    } else {
                        // User not found in DB (maybe cleared), clean up local storage
                        localStorage.removeItem('vibe_currentUserId');
                    }
                }
            } catch (error) {
                console.error("Failed to load persistent state:", error);
                setCurrentUser(null);
            } finally {
                setIsLoading(false);
            }
        };

        initData();
    }, []);

    // Persist active project selection to localStorage
    useEffect(() => {
        if (currentUser) {
            if (project) {
                localStorage.setItem(`activeProject_${currentUser.id}`, project.id);
            } else {
                localStorage.removeItem(`activeProject_${currentUser.id}`);
            }
        }
    }, [currentUser, project]);

    const updateProject = (updatedProject: Project) => {
        setProjects(prevProjects => {
            const projectExists = prevProjects.some(p => p.id === updatedProject.id);
            if (projectExists) {
                return prevProjects.map(p => p.id === updatedProject.id ? updatedProject : p);
            } else {
                return [...prevProjects, updatedProject];
            }
        });
        if (project && project.id === updatedProject.id) {
            setProject(updatedProject);
        }
        // Async persistence
        dbService.saveProject(updatedProject).catch(console.error);
    };

    const addProject = (newProject: Project) => {
        setProjects(prev => [...prev, newProject]);
        dbService.saveProject(newProject).catch(console.error);
    };

    const deleteProject = (projectId: string) => {
        setProjects(prev => prev.filter(p => p.id !== projectId));
        if (project?.id === projectId) {
            setProject(null);
        }
        dbService.deleteProject(projectId).catch(console.error);
    };

    const updateProjectDetails = (projectId: string, updates: { requirements: string, constraints: string }) => {
        const updateFn = (p: Project) => p.id === projectId ? { ...p, ...updates } : p;

        let updatedProject: Project | undefined;
        setProjects(prev => {
            const next = prev.map(updateFn);
            updatedProject = next.find(p => p.id === projectId);
            return next;
        });

        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const updatePhase = (projectId: string, phaseId: string, updates: Partial<Phase>) => {
        let updatedProject: Project | undefined;

        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedPhases = p.phases.map(ph => ph.id === phaseId ? { ...ph, ...updates } : ph);
                updatedProject = { ...p, phases: updatedPhases };
                return updatedProject;
            }
            return p;
        };

        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const addComment = (projectId: string, phaseId: string, text: string) => {
        if (!currentUser) return;
        const newComment: Comment = {
            id: generateUUID(),
            userId: currentUser.id,
            phaseId, text, createdAt: new Date()
        };

        let updatedProject: Project | undefined;
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedComments = { ...p.comments };
                if (!updatedComments[phaseId]) updatedComments[phaseId] = [];
                updatedComments[phaseId].push(newComment);
                updatedProject = { ...p, comments: updatedComments };
                return updatedProject;
            }
            return p;
        };

        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const addTask = (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => {
         const newTask: Task = { ...task, id: generateUUID(), createdAt: new Date() };
         let updatedProject: Project | undefined;

         const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = [...(p.tasks || []), newTask];
                updatedProject = { ...p, tasks: updatedTasks };
                return updatedProject;
            }
            return p;
         };

         setProjects(prev => prev.map(updateFn));
         if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

         if (updatedProject) {
             dbService.saveProject(updatedProject).catch(console.error);
         }
    };

    const updateTask = (projectId: string, updatedTask: Task) => {
        let updatedProject: Project | undefined;
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = (p.tasks || []).map(t => t.id === updatedTask.id ? updatedTask : t);
                updatedProject = { ...p, tasks: updatedTasks };
                return updatedProject;
            }
            return p;
         };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const login = async (email: string, pass: string): Promise<boolean> => {
        try {
            const user = await dbService.getUser(email);

            if (!user) return false;

            // New verification for hashed passwords
            if (user.passwordHash && !user.passwordHash.startsWith('mock_hash_')) {
                const isValid = await verifyPassword(pass, user.passwordHash);
                if (isValid) {
                    setCurrentUser(user);
                    localStorage.setItem('vibe_currentUserId', user.id);
                    const userProjects = await dbService.getProjects(user.id);
                    setProjects(userProjects);
                    return true;
                }
            }
            // Legacy support for mock hashes and users without hashes (migration path)
            else if (!user.passwordHash || user.passwordHash === `mock_hash_${pass}` || user.passwordHash === `mock_hash_${btoa(pass)}`) {
                setCurrentUser(user);
                localStorage.setItem('vibe_currentUserId', user.id);
                const userProjects = await dbService.getProjects(user.id);
                setProjects(userProjects);
                return true;
            }

            return false;
        } catch (error) {
            console.error("Login error:", error);
            return false;
        }
    };

    const signup = async (name: string, email: string, pass: string): Promise<boolean> => {
        try {
            const existingUser = await dbService.getUser(email);
            if (existingUser) {
                return false;
            }

            const passwordHash = await hashPassword(pass);

            const newUser: User = { 
                id: generateUUID(), 
                name, 
                email, 
                role: 'Engineer', 
                avatar: '👤',
                passwordHash: passwordHash
            };

            await dbService.saveUser(newUser);
            setCurrentUser(newUser);
            localStorage.setItem('vibe_currentUserId', newUser.id);
            setProjects([]); // New user has no projects
            return true;
        } catch (error) {
            console.error("Signup error:", error);
            return false;
        }
    };

    const updateUserProfile = (updates: Partial<User>) => {
        if (!currentUser) return;
        const updatedUser = { ...currentUser, ...updates };
        setCurrentUser(updatedUser);

        // Update in DB
        dbService.saveUser(updatedUser).catch(console.error);
    };

    const logout = () => {
        if (currentUser) {
            localStorage.removeItem(`activeProject_${currentUser.id}`);
        }
        setCurrentUser(null);
        setProject(null);
        localStorage.removeItem('vibe_currentUserId');
        setProjects([]);
    };

    if (isLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-charcoal-900 text-gray-900 dark:text-white">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-primary"></div>
            </div>
        );
    }

    return (
        <ProjectContext.Provider value={{ 
            project, setProject, 
            projects,
            currentUser,
            setCurrentUser,
            theme, setTheme,
            login, signup, logout, updateUserProfile,
            updateProject, addProject, deleteProject, updateProjectDetails, updatePhase, addComment, addTask, updateTask,
            isLoading
        }}>
            {children}
        </ProjectContext.Provider>
    );
};

export const useProject = (): ProjectContextType => {
    const context = useContext(ProjectContext);
    if (context === undefined) {
        throw new Error('useProject must be used within a ProjectProvider');
    }
    return context;
};

import React, { useState } from 'react';
import { X, Save, Download, Upload, User, BrainCircuit, LoaderCircle } from 'lucide-react';
import { useProject } from '../context/ProjectContext';
import { Button, Card } from './ui';
import { ToastMessage, Project } from '../types';
import { dbService } from '../services/db';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    setToast: (toast: ToastMessage | null) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, setToast }) => {
    const { currentUser, updateUserProfile, project, updateProject, projects, addProject } = useProject();
    const [name, setName] = useState(currentUser?.name || '');
    const [email, setEmail] = useState(currentUser?.email || '');
    const [occupation, setOccupation] = useState(currentUser?.occupation || '');
    const [aiModel, setAiModel] = useState(project?.aiModel || 'gemini-3-flash-preview');
    const [isSaving, setIsSaving] = useState(false);

    if (!isOpen) return null;

    const handleSave = () => {
        setIsSaving(true);
        updateUserProfile({ name, email, occupation });
        if (project) {
            updateProject({ ...project, aiModel });
        }
        setToast({ message: 'Settings updated successfully.', type: 'success' });
        setTimeout(() => {
            setIsSaving(false);
            onClose();
        }, 500);
    };

    const handleFullBackup = () => {
        // Use projects from context which are loaded from DB
        const fullState = {
            currentUser,
            projects: projects, 
            settings: { theme: localStorage.getItem('theme'), aiModel }
        };
        const blob = new Blob([JSON.stringify(fullState, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `vibra_engineer_backup_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        setToast({ message: 'Full system backup downloaded.', type: 'success' });
    };

    const handleFullRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = async (event) => {
            try {
                const state = JSON.parse(event.target?.result as string);
                if (state.currentUser && state.projects) {
                    setIsSaving(true); // Show saving state during async restore

                    // Restore User to DB
                    await dbService.saveUser(state.currentUser);
                    localStorage.setItem('vibe_currentUserId', state.currentUser.id);

                    // Restore Projects to DB
                    // We iterate and save each project properly
                    if (Array.isArray(state.projects)) {
                        for (const p of state.projects) {
                            await dbService.saveProject(p);
                        }
                    }

                    // Restore Settings
                    if(state.settings?.theme) {
                        localStorage.setItem('theme', state.settings.theme);
                    }

                    setToast({ message: 'Full system restored. Reloading...', type: 'success' });
                    setTimeout(() => window.location.reload(), 1500);
                } else {
                    throw new Error('Invalid backup file structure.');
                }
            } catch (err: any) {
                console.error(err);
                setToast({ message: `Failed to restore backup: ${err.message}`, type: 'error' });
                setIsSaving(false);
            }
        };
        reader.readAsText(file);
    };

    return (
