export const generateDiagram = async (documentContent: string): Promise<string> => {
    const ai = getAi();

    // Step 1: Orchestrate the visual prompt using text model
    const orchestratorPrompt = `Analyze the following engineering document and create a highly detailed image generation prompt for a professional technical diagram (e.g., system architecture, block diagram, or flow-process chart). The prompt should be descriptive about layout, nodes, and connections.\n\nDOCUMENT:\n${documentContent.substring(0, 4000)}`;

    const orchestratorResponse = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: TEXT_MODEL,
        contents: orchestratorPrompt,
        config: { systemInstruction: "Output ONLY a descriptive prompt for an image generation model." }
    }));

    const detailedPrompt = orchestratorResponse.text;

    // Step 2: Generate the image using the image model
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: IMAGE_MODEL,
        contents: { parts: [{ text: `A professional, clean, high-resolution technical engineering diagram: ${detailedPrompt}. Minimal text, focus on structure.` }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
    }));

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data returned from AI model.");
};

