import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { Project, User, Phase, Comment, Task } from '../types';
import { hashPassword, verifyPassword, generateUUID } from '../utils/crypto';
import { dbService } from '../services/db';

interface ProjectContextType {
    project: Project | null;
    setProject: React.Dispatch<React.SetStateAction<Project | null>>;
    projects: Project[];
    currentUser: User | null;
    setCurrentUser: React.Dispatch<React.SetStateAction<User | null>>;
    theme: string;
    setTheme: (theme: string) => void;

    // Auth & Project list management
    login: (email: string, pass: string) => Promise<boolean>;
    signup: (name: string, email: string, pass: string) => Promise<boolean>;
    logout: () => void;
    updateUserProfile: (updates: Partial<User>) => void;

    // Project lifecycle management
    updateProject: (updatedProject: Project) => void;
    addProject: (newProject: Project) => void;
    deleteProject: (projectId: string) => void;
    updateProjectDetails: (projectId: string, updates: { requirements: string, constraints: string }) => void;
    updatePhase: (projectId: string, phaseId: string, updates: Partial<Phase>) => void;
    addComment: (projectId: string, phaseId: string, text: string) => void;
    addTask: (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => void;
    updateTask: (projectId: string, updatedTask: Task) => void;
    isLoading: boolean;
}

const ProjectContext = createContext<ProjectContextType | undefined>(undefined);

interface ProjectProviderProps {
    children?: ReactNode;
}

export const ProjectProvider = ({ children }: ProjectProviderProps) => {
    const [project, setProject] = useState<Project | null>(null);
    const [projects, setProjects] = useState<Project[]>([]);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [theme, setThemeState] = useState(() => {
        if (typeof window === 'undefined') return 'dark';
        return localStorage.getItem('theme') || 'dark';
    });

    const setTheme = (newTheme: string) => {
        if (newTheme === 'dark') {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
        localStorage.setItem('theme', newTheme);
        setThemeState(newTheme);
    };

    useEffect(() => {
        setTheme(theme);
    }, []);

    // Load current user and projects from DB on initial load
    useEffect(() => {
        const initData = async () => {
            setIsLoading(true);
            try {
                const savedUserId = localStorage.getItem('vibe_currentUserId');
                if (savedUserId) {
                    const user = await dbService.getUserById(savedUserId);
                    if (user) {
                        setCurrentUser(user);

                        // Load projects for this user
                        const userProjects = await dbService.getProjects(user.id);
                        setProjects(userProjects);

                        // Load active project ID if user exists
                        const activeProjectId = localStorage.getItem(`activeProject_${user.id}`);
                        if (activeProjectId) {
                            const activeProject = userProjects.find((p: Project) => p.id === activeProjectId);
                            if (activeProject) setProject(activeProject);
                        }
                    } else {
                        // User ID in local storage is invalid/deleted
                        localStorage.removeItem('vibe_currentUserId');
                    }
                }
            } catch (error) {
                console.error("Failed to load persistent state:", error);
            } finally {
                setIsLoading(false);
            }
        };

        initData();
    }, []);

    // Persist active project selection to localStorage
    useEffect(() => {
        if (currentUser) {
            if (project) {
                localStorage.setItem(`activeProject_${currentUser.id}`, project.id);
            } else {
                localStorage.removeItem(`activeProject_${currentUser.id}`);
            }
        }
    }, [currentUser, project]);

    const updateProject = (updatedProject: Project) => {
        setProjects(prevProjects => {
            const projectExists = prevProjects.some(p => p.id === updatedProject.id);
            if (projectExists) {
                return prevProjects.map(p => p.id === updatedProject.id ? updatedProject : p);
            } else {
                return [...prevProjects, updatedProject];
            }
        });
        if (project && project.id === updatedProject.id) {
            setProject(updatedProject);
        }
        // Async persistence
        dbService.saveProject(updatedProject).catch(err => console.error("Failed to save project update:", err));
    };

    const addProject = (newProject: Project) => {
        setProjects(prev => [...prev, newProject]);
        dbService.saveProject(newProject).catch(console.error);
    };

    const deleteProject = (projectId: string) => {
        setProjects(prev => prev.filter(p => p.id !== projectId));
        if (project?.id === projectId) {
            setProject(null);
        }
        dbService.deleteProject(projectId).catch(console.error);
    };

    const updateProjectDetails = (projectId: string, updates: { requirements: string, constraints: string }) => {
        const updateFn = (p: Project) => p.id === projectId ? { ...p, ...updates } : p;

        let updatedProject: Project | undefined;
        setProjects(prev => {
            const next = prev.map(updateFn);
            updatedProject = next.find(p => p.id === projectId);
            return next;
        });

        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const updatePhase = (projectId: string, phaseId: string, updates: Partial<Phase>) => {
        let updatedProject: Project | undefined;

        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedPhases = p.phases.map(ph => ph.id === phaseId ? { ...ph, ...updates } : ph);
                updatedProject = { ...p, phases: updatedPhases };
                return updatedProject;
            }
            return p;
        };

        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const addComment = (projectId: string, phaseId: string, text: string) => {
        if (!currentUser) return;
        const newComment: Comment = {
            id: generateUUID(),
            userId: currentUser.id,
            phaseId, text, createdAt: new Date()
        };

        let updatedProject: Project | undefined;
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedComments = { ...p.comments };
                if (!updatedComments[phaseId]) updatedComments[phaseId] = [];
                updatedComments[phaseId].push(newComment);
                updatedProject = { ...p, comments: updatedComments };
                return updatedProject;
            }
            return p;
        };

        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const addTask = (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => {
         const newTask: Task = { ...task, id: generateUUID(), createdAt: new Date() };
         let updatedProject: Project | undefined;

         const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = [...(p.tasks || []), newTask];
                updatedProject = { ...p, tasks: updatedTasks };
                return updatedProject;
            }
            return p;
         };

         setProjects(prev => prev.map(updateFn));
         if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

         if (updatedProject) {
             dbService.saveProject(updatedProject).catch(console.error);
         }
    };

    const updateTask = (projectId: string, updatedTask: Task) => {
        let updatedProject: Project | undefined;
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = (p.tasks || []).map(t => t.id === updatedTask.id ? updatedTask : t);
                updatedProject = { ...p, tasks: updatedTasks };
                return updatedProject;
            }
            return p;
         };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);

        if (updatedProject) {
            dbService.saveProject(updatedProject).catch(console.error);
        }
    };

    const login = async (email: string, pass: string): Promise<boolean> => {
        try {
            const normalizedEmail = email.toLowerCase().trim();
            const user = await dbService.getUser(normalizedEmail);

            if (!user) return false;

            // New verification for hashed passwords
            if (user.passwordHash && !user.passwordHash.startsWith('mock_hash_')) {
                const isValid = await verifyPassword(pass, user.passwordHash);
                if (isValid) {
                    setCurrentUser(user);
                    localStorage.setItem('vibe_currentUserId', user.id);
                    const userProjects = await dbService.getProjects(user.id);
                    setProjects(userProjects);
                    return true;
                }
            }
            // Legacy support for mock hashes and users without hashes (migration path)
            else if (!user.passwordHash || user.passwordHash === `mock_hash_${pass}` || user.passwordHash === `mock_hash_${btoa(pass)}`) {
                setCurrentUser(user);
                localStorage.setItem('vibe_currentUserId', user.id);
                const userProjects = await dbService.getProjects(user.id);
                setProjects(userProjects);
                return true;
            }

            return false;
        } catch (error) {
            console.error("Login error:", error);
            return false;
        }
    };

    const signup = async (name: string, email: string, pass: string): Promise<boolean> => {
        try {
            const normalizedEmail = email.toLowerCase().trim();
            const existingUser = await dbService.getUser(normalizedEmail);
            if (existingUser) {
                return false;
            }

            const passwordHash = await hashPassword(pass);

            const newUser: User = { 
                id: generateUUID(), 
                name, 
                email: normalizedEmail, 
                role: 'Engineer', 
                avatar: '👤',
                passwordHash: passwordHash
            };

            await dbService.saveUser(newUser);
            setCurrentUser(newUser);
            localStorage.setItem('vibe_currentUserId', newUser.id);
            setProjects([]); // New user has no projects
            return true;
        } catch (error) {
            console.error("Signup error:", error);
            return false;
        }
    };

    const updateUserProfile = (updates: Partial<User>) => {
        if (!currentUser) return;
        const updatedUser = { ...currentUser, ...updates };
        setCurrentUser(updatedUser);

        // Update in DB
        dbService.saveUser(updatedUser).catch(console.error);
    };

    const logout = () => {
        if (currentUser) {
            localStorage.removeItem(`activeProject_${currentUser.id}`);
        }
        setCurrentUser(null);
        setProject(null);
        localStorage.removeItem('vibe_currentUserId');
        setProjects([]);
    };

    if (isLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-charcoal-900 text-gray-900 dark:text-white">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-primary"></div>
            </div>
        );
    }

    return (
        <ProjectContext.Provider value={{ 
            project, setProject, 
            projects,
            currentUser,
            setCurrentUser,
            theme, setTheme,
            login, signup, logout, updateUserProfile,
            updateProject, addProject, deleteProject, updateProjectDetails, updatePhase, addComment, addTask, updateTask,
            isLoading
        }}>
            {children}
        </ProjectContext.Provider>
    );
};

export const useProject = (): ProjectContextType => {
    const context = useContext(ProjectContext);
    if (context === undefined) {
        throw new Error('useProject must be used within a ProjectProvider');
    }
    return context;
};

